import React, { useState, useEffect } from 'react';

const ProductList = () => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(false);
  const [filters, setFilters] = useState({
    category: '',
    search: '',
    sort: ''
  });

  useEffect(() => {
    fetchProducts();
  }, [filters]);

  const fetchProducts = async () => {
    setLoading(true);
    try {
      // Fetch from dummyjson.com
      let url = 'https://dummyjson.com/products';
      
      // Add search query if provided
      if (filters.search) {
        url = `https://dummyjson.com/products/search?q=${filters.search}`;
      }
      
      const response = await fetch(url);
      const data = await response.json();
      
      // Electronics categories only
      const electronicsCategories = ['smartphones', 'laptops', 'tablets', 'computer-accessories', 'monitors', 'tv'];
      
      let processedProducts = (data.products || []).filter(p => 
        electronicsCategories.includes(p.category)
      );
      
      // Filter by category if selected
      if (filters.category) {
        processedProducts = processedProducts.filter(p => p.category === filters.category);
      }
      
      // Sort products
      if (filters.sort === 'price-asc') {
        processedProducts.sort((a, b) => a.price - b.price);
      } else if (filters.sort === 'price-desc') {
        processedProducts.sort((a, b) => b.price - a.price);
      } else if (filters.sort === 'rating') {
        processedProducts.sort((a, b) => b.rating - a.rating);
      }
      
      setProducts(processedProducts);
    } catch (error) {
      console.error('Failed to fetch products:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleFilterChange = (e) => {
    const { name, value } = e.target;
    setFilters(prev => ({
      ...prev,
      [name]: value
    }));
  };

  return (
    <div className="product-list">
      <div className="filters">
        <input
          type="text"
          name="search"
          placeholder="Search products..."
          value={filters.search}
          onChange={handleFilterChange}
        />
        <select name="category" value={filters.category} onChange={handleFilterChange}>
          <option value="">All Electronics</option>
          <option value="smartphones">Smartphones</option>
          <option value="laptops">Laptops</option>
          <option value="tablets">Tablets</option>
          <option value="computer-accessories">Computer Accessories</option>
          <option value="monitors">Monitors</option>
          <option value="tv">TV</option>
        </select>
        <select name="sort" value={filters.sort} onChange={handleFilterChange}>
          <option value="">Sort By</option>
          <option value="price-asc">Price: Low to High</option>
          <option value="price-desc">Price: High to Low</option>
          <option value="rating">Best Rating</option>
        </select>
      </div>

      {loading ? (
        <div>Loading products...</div>
      ) : (
        <div className="products-grid">
          {products.map(product => (
            <div key={product.id} className="product-card">
              <img src={product.thumbnail} alt={product.title} />
              <h3>{product.title}</h3>
              <p className="price">₹{Math.round(product.price * 83)}</p>
              <p className="description">{product.description.substring(0, 50)}...</p>
              <div className="rating">⭐ {product.rating}</div>
              <button className="view-btn">View Details</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default ProductList;
